  2→import { watch, type FSWatcher } from 'node:fs';
  3→import { basename, dirname, join } from 'node:path';
  4→import { makeAgentLabel } from '../core/detector-interfaces.ts';
  5→import type {
  6→  OutputHandler,
  7→  SessionHandler,
  8→  WatcherHandler,
  9→  RetryConfig,
 10→} from '../core/detector-interfaces.ts';
 11→
 12→// Re-export for backward compatibility (consumers can still import from this file)
 13→export type {
 14→  OutputHandler,
 15→  SessionHandler,
 16→  WatcherHandler,
 17→  RetryConfig,
 18→} from '../core/detector-interfaces.ts';
 19→export {
 20→  MAIN_LABEL,
 21→  makeAgentLabel,
 22→  extractAgentIdFromLabel,
 23→} from '../core/detector-interfaces.ts';
 24→
 25→/**
 26→ * SubagentDetector 配置
 27→ */
 28→export interface SubagentDetectorConfig {
 29→  /** subagents 目錄路徑 */
 30→  subagentsDir: string;
 31→  /** 輸出處理器 */
 32→  output: OutputHandler;
 33→  /** Watcher 處理器 */
 34→  watcher: WatcherHandler;
 35→  /** Session 處理器（可選，Interactive 模式使用） */
 36→  session?: SessionHandler;
 37→  /** 是否啟用（對應 options.follow） */
 38→  enabled: boolean;
 39→  /** 是否啟用目錄監控（預設 true） */
 40→  watchDir?: boolean;
 41→  /** 新 subagent 偵測時的回呼（用於 pane 自動開啟等） */
 42→  onNewSubagent?: (
 43→    agentId: string,
 44→    subagentPath: string,
 45→    description?: string
 46→  ) => void;
 47→  /** Subagent 進入時的回呼（含 resume，每次進入都觸發，用於 pane 開啟） */
 48→  onSubagentEnter?: (agentId: string, subagentPath: string) => void;
 49→  /** Subagent 完成時的回呼（用於 pane 自動關閉等） */
 50→  onSubagentDone?: (agentId: string) => void;
 51→  /** 檢查 agentId 是否有對應的 pane（用於判斷是否需要關閉） */
 52→  hasPane?: (agentId: string) => boolean;
 53→}
 54→
 55→// ============================================================
 56→// Constants
 57→// ============================================================
 58→
 59→/** Early detection 預設配置 */
 60→export const EARLY_DETECTION_RETRY: RetryConfig = {
 61→  maxRetries: 10,
 62→  retryDelay: 100,
 63→  initialDelay: 50,
 64→};
 65→
 66→/** Fallback detection 預設配置 */
 67→export const FALLBACK_DETECTION_RETRY: RetryConfig = {
 68→  maxRetries: 5,
 69→  retryDelay: 100,
 70→  initialDelay: 100,
 71→};
 72→
 73→/** 建立 subagent 檔案路徑 */
 74→export function buildSubagentPath(
 75→  subagentsDir: string,
 76→  agentId: string
 77→): string {
 78→  return join(subagentsDir, `agent-${agentId}.jsonl`);
 79→}
 80→
 81→/** 從 session 檔案路徑推導 subagents 目錄 */
 82→export function getSubagentsDir(sessionFilePath: string): string {
 83→  const projectDir = dirname(sessionFilePath);
 84→  const sessionId = basename(sessionFilePath, '.jsonl');
 85→  return join(projectDir, sessionId, 'subagents');
 86→}
 87→
 88→// ============================================================
 89→// Utility Functions
 90→// ============================================================
 91→
 92→/**
 93→ * 驗證 agentId 格式
 94→ * 支援 7-40 位十六進制字符（涵蓋短 hash 到完整 SHA-1）
 95→ * 同時防止路徑穿越攻擊
 96→ */
 97→export function isValidAgentId(agentId: string): boolean {
 98→  return /^[0-9a-f]{7,40}$/i.test(agentId);
 99→}
100→
101→/**
102→ * 從主 session 檔案中提取所有 agentId
103→ */
104→export async function extractAgentIds(
105→  sessionPath: string
106→): Promise<Set<string>> {
107→  const agentIds = new Set<string>();
108→
109→  try {
110→    const file = Bun.file(sessionPath);
111→    const content = await file.text();
112→    const lines = content.split('\n').filter(Boolean);
113→
114→    for (const line of lines) {
115→      try {
116→        const data = JSON.parse(line);
117→        // 從 toolUseResult 中提取 agentId，並驗證格式以防止路徑穿越
118→        const agentId = data.toolUseResult?.agentId;
119→        if (agentId && isValidAgentId(agentId)) {
120→          agentIds.add(agentId);
121→        }
122→      } catch {
123→        // 忽略解析錯誤
124→      }
125→    }
126→  } catch {
127→    // 忽略檔案讀取錯誤
128→  }
129→
130→  return agentIds;
131→}
132→
133→/**
134→ * 掃描 subagents 目錄，找出尚未被監控的新 subagent 檔案
135→ * @param subagentsDir subagents 目錄路徑
136→ * @param knownAgentIds 已知的 agentId 集合
137→ * @returns 新發現的 agentId 陣列
138→ */
139→export async function scanForNewSubagents(
140→  subagentsDir: string,
141→  knownAgentIds: Set<string>
142→): Promise<string[]> {
143→  const newAgentIds: string[] = [];
144→
145→  try {
146→    const glob = new Glob('agent-*.jsonl');
147→    for await (const file of glob.scan({ cwd: subagentsDir })) {
148→      // 從檔名 "agent-{id}.jsonl" 提取 id（支援 7-40 位 hex）
149→      const match = file.match(/^agent-([0-9a-f]{7,40})\.jsonl$/i);
150→      if (match && match[1]) {
151→        const agentId = match[1];
152→        if (!knownAgentIds.has(agentId)) {
153→          newAgentIds.push(agentId);
154→        }
155→      }
156→    }
157→  } catch {
158→    // 目錄不存在或無法存取時靜默忽略
159→    // 這是預期行為：subagent 可能尚未建立目錄
160→  }
161→
162→  return newAgentIds;
163→}
164→
165→// ============================================================
166→// Core Functions
167→// ============================================================
168→
169→/**
170→ * 嘗試新增 subagent 檔案監控（含重試邏輯）
171→ *
172→ * @param subagentPath - subagent 檔案路徑
173→ * @param agentId - agent 識別碼
174→ * @param watcher - watcher 處理器
175→ * @param output - 輸出處理器
176→ * @param config - 重試配置
177→ * @returns Promise<boolean> 是否成功新增
178→ */
179→export async function tryAddSubagentFile(
180→  subagentPath: string,
181→  agentId: string,
182→  watcher: WatcherHandler,
183→  output: OutputHandler,
184→  config: RetryConfig = FALLBACK_DETECTION_RETRY
185→): Promise<boolean> {
186→  const doTry = async (retriesLeft: number): Promise<boolean> => {
187→    try {
188→      const file = Bun.file(subagentPath);
189→      if (await file.exists()) {
190→        await watcher.addFile({
191→          path: subagentPath,
192→          label: makeAgentLabel(agentId),
193→        });
194→        return true;
195→      } else if (retriesLeft > 0) {
196→        await new Promise((resolve) => setTimeout(resolve, config.retryDelay));
197→        return doTry(retriesLeft - 1);
198→      } else {
199→        output.debug(`Subagent file not found after retries: ${agentId}`);
200→        return false;
201→      }
202→    } catch (error) {
203→      output.error(`Failed to add subagent watcher: ${agentId} - ${error}`);
204→      return false;
205→    }
206→  };
207→
208→  // 初始延遲後開始嘗試
209→  await new Promise((resolve) => setTimeout(resolve, config.initialDelay));
210→  return doTry(config.maxRetries);
211→}
212→
213→// ============================================================
214→// SubagentDetector Class
215→// ============================================================
216→
217→/**
218→ * Subagent 偵測器 - 整合 early detection 和 fallback detection
219→ */
220→export class SubagentDetector {
221→  private knownAgentIds: Set<string>;
222→  private config: SubagentDetectorConfig;
223→  private dirWatcher: FSWatcher | null = null;
224→  private parentWatcher: FSWatcher | null = null;
225→  private scanTimer: ReturnType<typeof setTimeout> | null = null;
226→  private isWatching = false;
227→  // 追蹤所有 pending 的 setTimeout 句柄，用於 stop() 時清除
228→  private pendingTimers: Set<ReturnType<typeof setTimeout>> = new Set();
229→  // FIFO queue: Task tool_use descriptions, matched to agents in registration order.
230→  // May mismatch with parallel Task launches (known limitation, wrong label only).
231→  private pendingDescriptions: string[] = [];
232→
233→  constructor(initialAgentIds: Set<string>, config: SubagentDetectorConfig) {
234→    this.knownAgentIds = new Set(initialAgentIds);
235→    this.config = config;
236→  }
237→
238→  /**
239→   * 啟動 subagents 目錄監控（自動偵測新檔案）
240→   */
241→  startDirectoryWatch(): void {
242→    if (!this.config.enabled) return;
243→    if (this.isWatching) return;
244→    if (this.config.watchDir === false) return;
245→
246→    this.isWatching = true;
247→    this.tryWatchSubagentsDir();
248→  }
249→
250→  /**
251→   * 停止所有監控
252→   */
253→  stop(): void {
254→    this.isWatching = false;
255→    this.clearScanTimer();
256→    // 清除所有 pending 的 setTimeout
257→    for (const timer of this.pendingTimers) {
258→      clearTimeout(timer);
259→    }
260→    this.pendingTimers.clear();
261→    this.pendingDescriptions = [];
262→    this.dirWatcher?.close();
263→    this.dirWatcher = null;
264→    this.parentWatcher?.close();
265→    this.parentWatcher = null;
266→  }
267→
268→  /**
269→   * 處理 early subagent detection（Task tool_use 觸發）
270→   * 使用非同步 setTimeout 來避免阻塞主流程
271→   */
272→  handleEarlyDetection(): void {
273→    if (!this.config.enabled) return;
274→
275→    // 延遲掃描（讓檔案有機會建立）
276→    const timer = setTimeout(async () => {
277→      this.pendingTimers.delete(timer);
278→      if (!this.isWatching) return;
279→
280→      try {
281→        const newAgentIds = await scanForNewSubagents(
282→          this.config.subagentsDir,
283→          this.knownAgentIds
284→        );
285→
286→        for (const agentId of newAgentIds) {
287→          this.registerNewAgent(
288→            agentId,
289→            EARLY_DETECTION_RETRY,
290→            `Early subagent detected: ${agentId}`
291→          );
292→        }
293→      } catch (error) {
294→        this.config.output.error(`Early detection scan failed: ${error}`);
295→      }
296→    }, EARLY_DETECTION_RETRY.initialDelay);
297→    this.pendingTimers.add(timer);
298→  }
299→
300→  /**
301→   * 處理 agent_progress 事件（subagent 進入或 resume 時）
302→   * 只在 resume（已知 agentId）時觸發 onSubagentEnter
303→   * 新 agentId 的 pane 開啟由 onNewSubagent 負責，避免重複觸發
304→   */
305→  handleAgentProgress(agentId: string): void {
306→    if (!this.config.enabled) return;
307→    if (!isValidAgentId(agentId)) return;
308→
309→    // 新 agentId 仍由 early/fallback 路徑完成註冊，避免提前標記 known 造成漏註冊
310→    if (!this.knownAgentIds.has(agentId)) return;
311→
312→    const subagentPath = buildSubagentPath(this.config.subagentsDir, agentId);
313→    this.config.onSubagentEnter?.(agentId, subagentPath);
314→  }
315→
316→  /**
317→   * 處理 fallback detection（toolUseResult 觸發）
318→   * @param agentId - 從 toolUseResult 提取的 agentId
319→   */
320→  handleFallbackDetection(agentId: string): void {
321→    // 驗證 agentId 格式
322→    if (!isValidAgentId(agentId)) {
323→      this.config.output.debug(`Ignoring invalid agentId format: ${agentId}`);
324→      return;
325→    }
326→
327→    // 檢查是否已經監控中
328→    const isAlreadyMonitored = this.knownAgentIds.has(agentId);
329→
330→    if (isAlreadyMonitored) {
331→      // 已經監控中，表示之前透過 early detection 發現過
332→      // 輸出完成訊息，觸發 onSubagentDone（關閉 pane）
333→      this.config.output.warn(`Subagent completed: ${agentId}`);
334→    } else {
335→      // 首次發現且已完成：不開 pane，只註冊監控
336→      this.knownAgentIds.add(agentId);
337→
338→      // Consume pending description to prevent queue drift
339→      // (this agent's Task tool_use pushed a description, but no pane will open)
340→      this.pendingDescriptions.shift();
341→
342→      const subagentPath = buildSubagentPath(this.config.subagentsDir, agentId);
343→
344→      // Session 處理（Interactive 模式）
345→      this.config.session?.addSession?.(
346→        agentId,
347→        makeAgentLabel(agentId),
348→        subagentPath
349→      );
350→
351→      if (this.config.enabled) {
352→        this.config.output.warn(
353→          `New subagent detected (completed): ${agentId}`
354→        );
355→
356→        // 非阻塞式新增檔案監控（但不觸發 onNewSubagent，因為已完成）
357→        // 只在 directory watch 已啟動時才建立 timer，避免孤立 timer 洩漏
358→        if (this.isWatching) {
359→          const timer = setTimeout(() => {
360→            this.pendingTimers.delete(timer);
361→            if (!this.isWatching) return;
362→
363→            tryAddSubagentFile(
364→              subagentPath,
365→              agentId,
366→              this.config.watcher,
367→              this.config.output,
368→              FALLBACK_DETECTION_RETRY
369→            );
370→          }, FALLBACK_DETECTION_RETRY.initialDelay);
371→          this.pendingTimers.add(timer);
372→        }
373→      }
374→    }
375→
376→    // toolUseResult 表示 subagent 已完成
377→    if (this.config.session?.markSessionDone) {
378→      this.config.session.markSessionDone(agentId);
379→      this.config.output.debug(`Subagent completed: ${agentId}`);
380→    }
381→    this.config.session?.updateUI?.();
382→
383→    // 只有已監控的（有開 pane 的）才需要觸發 onSubagentDone
384→    if (isAlreadyMonitored && this.config.hasPane?.(agentId)) {
385→      this.config.onSubagentDone?.(agentId);
386→    }
387→  }
388→
389→  /**
390→   * Push a Task description to the FIFO queue.
391→   * Called when a Task tool_use with description is detected in the main session.
392→   * The description will be matched to the next newly registered agent.
393→   */
394→  pushDescription(description: string): void {
395→    this.pendingDescriptions.push(description);
396→  }
397→
398→  /**
399→   * 取得已知的 agentId 集合（供測試使用）
400→   */
401→  getKnownAgentIds(): Set<string> {
402→    return new Set(this.knownAgentIds);
403→  }
404→
405→  /**
406→   * 檢查是否為已知的 agentId
407→   */
408→  isKnownAgent(agentId: string): boolean {
409→    return this.knownAgentIds.has(agentId);
410→  }
411→
412→  private clearScanTimer(): void {
413→    if (this.scanTimer) {
414→      clearTimeout(this.scanTimer);
415→      this.scanTimer = null;
416→    }
417→  }
418→
419→  private scheduleScan(): void {
420→    if (!this.isWatching) return;
421→    this.clearScanTimer();
422→    this.scanTimer = setTimeout(async () => {
423→      if (!this.isWatching) return;
424→      try {
425→        const newAgentIds = await scanForNewSubagents(
426→          this.config.subagentsDir,
427→          this.knownAgentIds
428→        );
429→        for (const agentId of newAgentIds) {
430→          this.registerNewAgent(
431→            agentId,
432→            EARLY_DETECTION_RETRY,
433→            `New subagent detected: ${agentId}`
434→          );
435→        }
436→      } catch (error) {
437→        this.config.output.error(`Directory scan failed: ${error}`);
438→      }
439→    }, 100);
440→  }
441→
442→  private tryWatchSubagentsDir(): void {
443→    if (!this.isWatching) return;
444→
445→    try {
446→      this.parentWatcher?.close();
447→      this.parentWatcher = null;
448→
449→      this.dirWatcher = watch(this.config.subagentsDir, () => {
450→        this.scheduleScan();
451→      });
452→      this.dirWatcher.on('error', () => {
453→        this.dirWatcher?.close();
454→        this.dirWatcher = null;
455→      });
456→      // 目錄建立後先掃描一次，避免錯過已存在的新檔案
457→      this.scheduleScan();
458→    } catch {
459→      // subagents 目錄可能尚未建立，改監控父層目錄
460→      this.watchParentForSubagentsDir();
461→    }
462→  }
463→
464→  private watchParentForSubagentsDir(): void {
465→    if (!this.isWatching) return;
466→    if (this.parentWatcher) return;
467→
468→    const parentDir = join(this.config.subagentsDir, '..');
469→    try {
470→      this.parentWatcher = watch(parentDir, () => {
471→        // 嘗試切回 subagents 目錄監控
472→        this.tryWatchSubagentsDir();
473→      });
474→      this.parentWatcher.on('error', () => {
475→        this.parentWatcher?.close();
476→        this.parentWatcher = null;
477→      });
478→    } catch {
479→      // ignore
480→    }
481→  }
482→
483→  private registerNewAgent(
484→    agentId: string,
485→    retryConfig: RetryConfig,
486→    message: string
487→  ): void {
488→    if (this.knownAgentIds.has(agentId)) return;
489→    this.knownAgentIds.add(agentId);
490→
491→    const subagentPath = join(
492→      this.config.subagentsDir,
493→      `agent-${agentId}.jsonl`
494→    );
495→
496→    // Session 處理（Interactive 模式）
497→    this.config.session?.addSession?.(
498→      agentId,
499→      makeAgentLabel(agentId),
500→      subagentPath
501→    );
502→
503→    if (this.config.enabled) {
504→      this.config.output.warn(message);
505→
506→      // 觸發 onNewSubagent 回呼（pane 自動開啟等用途）
507→      const description = this.pendingDescriptions.shift();
508→      this.config.onNewSubagent?.(agentId, subagentPath, description);
509→
510→      // 非阻塞式新增檔案監控
511→      const timer = setTimeout(() => {
512→        this.pendingTimers.delete(timer);
513→        if (!this.isWatching) return;
514→
515→        tryAddSubagentFile(
516→          subagentPath,
517→          agentId,
518→          this.config.watcher,
519→          this.config.output,
520→          retryConfig
521→        );
522→      }, retryConfig.initialDelay);
523→      this.pendingTimers.add(timer);
524→    }
525→  }
526→}
